mapper.update:
UPDATE student
student_number = #{studentNumber}, class_name = #{className}, major = #{major}, counselor_id = #{counselorId}, enrollment_date = #{enrollmentDate},
WHERE user_id = #{userId}

mapper.select:
SELECT s.*, u.real_name, u2.real_name as counselor_name, CASE WHEN a.status = 'ACTIVE' THEN 'ACTIVE' ELSE 'NONE' END as housing_status FROM student s LEFT JOIN user u ON s.user_id = u.id LEFT JOIN user u2 ON s.counselor_id = u2.id LEFT JOIN assignment a ON s.id = a.student_id AND a.status = 'ACTIVE'
AND s.class_name LIKE CONCAT('%', #{className}, '%')
AND s.major LIKE CONCAT('%', #{major}, '%')
AND s.counselor_id = #{counselorId}
ORDER BY s.student_number LIMIT #{offset}, #{limit}

SELECT * FROM student 
WHERE student_number = #{studentNumber} 
AND user_id != #{excludeUserId}

SELECT DISTINCT student_id FROM leave_request WHERE student_id IN
#{studentId}
AND status IN ('PENDING', 'APPROVED') AND ( (start_time <= #{startTime} AND end_time >= #{endTime}) OR (start_time <= #{startTime} AND end_time >= #{startTime}) OR (start_time <= #{endTime} AND end_time >= #{endTime}) )
